// // This module calculates the 2's complement of a 4-bit signed binary number. If the input is positive, it returns the same value; if negative, it returns the 2's complement.
module twos_comp(
    input signed [3:0] a,
    output reg signed [3:0] b
);

always @(*) begin
    if (a[3] == 0) begin // positive number
        b = a;
    end else begin // negative number
        b = ~a + 1;
    end
end

endmodule
